item.description:
 &lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;Lambda&lt;/code&gt;表达式是 &lt;code&gt;C++11&lt;/code&gt; 引入的一种匿名函数，允许在需要函数对象的地方直接定义一个函数，无需显式定义函数名。&lt;code&gt;Lambda&lt;/code&gt; 表达式常用于实现回调函数、临时函数、算法函数等场景。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1&gt;基本语法&lt;/h1&gt;
&lt;p&gt;Lambda 表达式的完整语法结构如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;[ captures ] ( params ) mutable -&amp;gt; return_type &amp;#123; body &amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;组成部分&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;[ captures ]&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;捕获列表，定义外部变量如何被 &lt;code&gt;Lambda&lt;/code&gt; 访问（值捕获、引用捕获等）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;( params )&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;参数列表，与普通函数参数列表一致&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;mutable&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;可选关键字，允许修改按值捕获的变量&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;-&amp;gt; return_type&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;可选返回类型，可省略（编译器自动推导）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;&amp;#123; body &amp;#125;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;Lambda&lt;/code&gt; 函数体&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h1&gt;捕获列表（Capture List）&lt;/h1&gt;
&lt;h2 id=&#34;捕获方式&#34;&gt;捕获方式&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;捕获方式&lt;/th&gt;
&lt;th&gt;语法示例&lt;/th&gt;
&lt;th&gt;行为&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;​按值捕获&lt;/td&gt;
&lt;td&gt;[x]&lt;/td&gt;
&lt;td&gt;复制外部变量 &lt;code&gt;x&lt;/code&gt; 的值到 &lt;code&gt;Lambda&lt;/code&gt; 内部&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​按引用捕获&lt;/td&gt;
&lt;td&gt;[&amp;amp;x]&lt;/td&gt;
&lt;td&gt;直接引用外部变量 &lt;code&gt;x&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​隐式按值捕获全部&lt;/td&gt;
&lt;td&gt;[=]&lt;/td&gt;
&lt;td&gt;按值捕获所有外部变量（不推荐，易导致悬空引用或性能问题）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​隐式按引用捕获全部&lt;/td&gt;
&lt;td&gt;[&amp;amp;]&lt;/td&gt;
&lt;td&gt;按引用捕获所有外部变量（不推荐，需谨慎管理生命周期）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​混合捕获&lt;/td&gt;
&lt;td&gt;&lt;code&gt;[x, &amp;amp;y]&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;按值捕获 &lt;code&gt;x&lt;/code&gt;，按引用捕获 &lt;code&gt;y&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​初始化捕获（C++14+）&lt;/td&gt;
&lt;td&gt;​	&lt;code&gt;[z = x + 1]&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;创建新变量 &lt;code&gt;z&lt;/code&gt;，其值为 &lt;code&gt;x + 1&lt;/code&gt;（可用于移动语义或复杂初始化）&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;示例代码&#34;&gt;示例代码&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int a = 1, b = 2;

// 按值捕获 a，按引用捕获 b
auto lambda1 = [a, &amp;amp;b]() &amp;#123; return a + b; &amp;#125;;

// 隐式按引用捕获所有外部变量
auto lambda2 = [&amp;amp;]() &amp;#123; a++; b++; &amp;#125;;

// 初始化捕获（C++14+）
auto lambda3 = [c = a * 2]() &amp;#123; return c; &amp;#125;; // c = 2
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;参数列表（Parameters）&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;与普通函数参数列表一致，支持值传递、引用传递、默认参数等。&lt;/li&gt;
&lt;li&gt;​无参数时可省略：&lt;code&gt;[] &amp;#123; ... &amp;#125;&lt;/code&gt;&lt;br&gt;
&lt;strong&gt;示例&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;auto add = [](int x, int y) &amp;#123; return x + y; &amp;#125;; // 值传递
auto print = [](const std::string&amp;amp; s) &amp;#123; std::cout &amp;lt;&amp;lt; s; &amp;#125;; // 引用传递
auto no_args = [] &amp;#123; return 42; &amp;#125;; // 无参数
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;mutable 关键字&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;默认情况下，按值捕获的变量在 &lt;code&gt;Lambda&lt;/code&gt; 内部是 ​不可修改 的。&lt;/li&gt;
&lt;li&gt;使用 &lt;code&gt;mutable&lt;/code&gt; 后，可以修改按值捕获的变量（修改的是副本，不影响外部变量）。&lt;br&gt;
&lt;strong&gt;示例&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int count = 0;

auto increment = [count]() mutable &amp;#123;
    count++; // 允许修改按值捕获的 count（副本）
&amp;#125;;

increment(); // 外部 count 仍为 0
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;返回类型（Return Type）&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;返回类型可省略，编译器根据 &lt;code&gt;return&lt;/code&gt; 语句自动推导。&lt;/li&gt;
&lt;li&gt;当函数体包含多个 &lt;code&gt;return&lt;/code&gt; 语句且类型不一致时，必须显式指定返回类型。&lt;br&gt;
&lt;strong&gt;示例&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;// 自动推导返回类型为 int
auto add = [](int x, int y) &amp;#123; return x + y; &amp;#125;;

// 显式指定返回类型为 double
auto divide = [](int x, int y) -&amp;gt; double &amp;#123;
    if (y == 0) return 0.0;
    return static_cast&amp;lt;double&amp;gt;(x) / y;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;Lambda 的应用场景&lt;/h1&gt;
&lt;h2 id=&#34;作为函数对象（Functor）&#34;&gt;作为函数对象（Functor）&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;std::vector&amp;lt;int&amp;gt; nums = &amp;#123;1, 2, 3, 4&amp;#125;;
std::sort(nums.begin(), nums.end(), [](int a, int b) &amp;#123;
    return a &amp;gt; b; // 降序排序
&amp;#125;);
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;异步回调（如-Boost-Asio）&#34;&gt;异步回调（如 Boost.Asio）&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;socket.async_read_some(buffer, [this](const error_code&amp;amp; ec, size_t bytes) &amp;#123;
    if (!ec) handle_read(bytes);
&amp;#125;);
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;封装局部逻辑&#34;&gt;封装局部逻辑&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void process_data(const std::vector&amp;lt;int&amp;gt;&amp;amp; data) &amp;#123;
    int threshold = 10;
    auto filter = [threshold](int x) &amp;#123; return x &amp;gt; threshold; &amp;#125;;
    std::copy_if(data.begin(), data.end(), std::back_inserter(result), filter);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;注意事项&lt;/h1&gt;
&lt;h2 id=&#34;生命周期管理&#34;&gt;生命周期管理&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;​按引用捕获：确保被引用的对象在 &lt;code&gt;Lambda&lt;/code&gt; 执行时仍然有效，避免悬空引用。&lt;/li&gt;
&lt;li&gt;​按值捕获指针：需谨慎，可能造成内存泄漏或悬空指针。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;性能&#34;&gt;性能&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;小对象按值捕获更高效，大对象（如容器）建议按引用捕获（需确保生命周期）。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;默认捕获的风险&#34;&gt;默认捕获的风险&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;避免使用 [=] 或 [&amp;amp;]：可能导致意外捕获不需要的变量，增加维护难度。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;Lambda-与函数对象的关系&#34;&gt;&lt;code&gt;Lambda&lt;/code&gt; 与函数对象的关系&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Lambda&lt;/code&gt; 本质上是编译器生成的匿名类（闭包类型）的实例。&lt;/li&gt;
&lt;li&gt;捕获的变量会成为该匿名类的成员变量。&lt;/li&gt;
&lt;li&gt;等价转换示例&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;// Lambda 表达式
auto lambda = [x](int y) &amp;#123; return x + y; &amp;#125;;

// 编译器生成的等价类
class __AnonymousClosure &amp;#123;
private:
    int x;
public:
    __AnonymousClosure(int x) : x(x) &amp;#123;&amp;#125;
    int operator()(int y) const &amp;#123; return x + y; &amp;#125;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;总结&lt;/h1&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;特性&lt;/th&gt;
&lt;th&gt;关键点&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;​捕获列表&lt;/td&gt;
&lt;td&gt;明确指定需要捕获的变量，避免隐式捕获&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​参数列表&lt;/td&gt;
&lt;td&gt;与普通函数一致，支持多种传递方式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​&lt;strong&gt;mutable&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;允许修改按值捕获的变量副本&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​返回类型&lt;/td&gt;
&lt;td&gt;可省略（自动推导）或显式指定&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​生命周期&lt;/td&gt;
&lt;td&gt;谨慎管理按引用捕获的变量，避免悬空引用&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​应用场景&lt;/td&gt;
&lt;td&gt;函数对象、异步回调、STL 算法等&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;

 &lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;Boost&lt;/code&gt; 是一个开源的 C++ 库集合，提供了许多实用的功能，如网络编程、图形界面、数学计算等。Boost 库可以与标准 C++ 库无缝集成，扩展了 C++ 的功能。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1&gt;安装 Boost 库&lt;/h1&gt;
&lt;p&gt;通过 APT 包管理器安装 Boost 库：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-shell&#34;&gt;# 1. 更新软件包索引
sudo apt update

# 2. 安装 Boost 核心库和开发文件（包含头文件和静态/动态库）
sudo apt install libboost-all-dev -y

# 3. 验证安装（检查版本）
boostversion=$(cat /usr/include/boost/version.hpp | grep &amp;quot;#define BOOST_VERSION&amp;quot; | awk &#39;&amp;#123;print $3&amp;#125;&#39;)

echo &amp;quot;Boost 版本: $boostversion&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;基本使用&lt;/h1&gt;
&lt;p&gt;同步操作会阻塞当前线程，直到操作完成。异步操作则不会阻塞线程，通过回调函数在操作完成后触发。&lt;/p&gt;
&lt;h2 id=&#34;同步&#34;&gt;同步&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;
#include &amp;lt;iostream&amp;gt;
#include&amp;lt;boost/asio.hpp&amp;gt;
int main()&amp;#123;
    boost::asio::io_context io;
    boost::asio::steady_timer t(io, boost::asio::chrono::seconds(5));
    // 同步,阻塞线程5秒
    t.wait();
    // wait() 返回，定时器资源（如系统句柄）被自动释放
    std::cout&amp;lt;&amp;lt;&amp;quot;Hello,world!&amp;quot;&amp;lt;&amp;lt;std::endl;
    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;定时器&lt;/strong&gt;&lt;br&gt;
&lt;code&gt;steady_timer&lt;/code&gt; 是 &lt;code&gt;Boost.Asio&lt;/code&gt; 提供的定时器类，用于在指定时间后执行回调函数。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;steady_timer &lt;/code&gt;的构造函数需要 &lt;code&gt;io_context&lt;/code&gt; 参数，目的是 &lt;strong&gt;​显式声明&lt;/strong&gt; 该定时器依赖** 的&lt;strong&gt;事件循环&lt;/strong&gt;。这种设计确保类型安全，避免隐式关联导致的错误。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;io_context 的作用&lt;/strong&gt;&lt;br&gt;
&lt;code&gt;io_context&lt;/code&gt; 是 &lt;code&gt;Boost.Asio&lt;/code&gt; 的核心组件，负责调度以及执行所有异步（如 DNS 解析、连接、读写）和同步操作的生命周期。（如定时器、网络 I/O）。&lt;/p&gt;
&lt;h2 id=&#34;异步&#34;&gt;异步&lt;/h2&gt;
&lt;p&gt;异步操作需要事件循环来驱动，&lt;code&gt;io_context::run()&lt;/code&gt; 方法启动事件处理流程。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;iostream&amp;gt;
#include&amp;lt;boost/asio.hpp&amp;gt;

void print(const boost::system::error_code&amp;amp; a /*e*/)
&amp;#123;
    std::cout&amp;lt;&amp;lt;a&amp;lt;&amp;lt;std::endl;
    std::cout&amp;lt;&amp;lt;&amp;quot;Hello,world!&amp;quot;&amp;lt;&amp;lt;std::endl;
&amp;#125;
int main()&amp;#123;
    boost::asio::io_context io;
    boost::asio::steady_timer t(io, boost::asio::chrono::seconds(5)); 
    t.async_wait(&amp;amp;print);   // 异步,不会阻塞线程，回调函数print会在5秒后执行
    io.run();
    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;io.run() &lt;/code&gt;是异步编程的核心，负责监听操作系统异步操作（如定时器到期、网络请求完成）的完成事件，确保资源（如&lt;code&gt;定时器&lt;/code&gt;、&lt;code&gt;socket&lt;/code&gt;）被正确释放，并触发回调函数。&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;特性&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;同步代码&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;异步代码&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​执行方式&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;阻塞等待（&lt;code&gt;wait()&lt;/code&gt;）&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;非阻塞，通过回调触发&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​事件循环&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;无需 &lt;code&gt;io.run()&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;必须调用 &lt;code&gt;io.run()&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​线程占用&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;单线程阻塞&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;单线程/多线程（由 &lt;code&gt;run()&lt;/code&gt; 决定）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​适用场景&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;简单、短耗时操作&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;高并发、实时性要求高的场景&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;p&gt;&lt;strong&gt;​时间点计算&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;函数式编程&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;functional&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

void print(const boost::system::error_code&amp;amp; /*e*/,
    boost::asio::steady_timer* t, int* count)
&amp;#123;
  if (*count &amp;lt; 5)
  &amp;#123;
    std::cout &amp;lt;&amp;lt; *count &amp;lt;&amp;lt; std::endl;
    ++(*count);

    // 新到期时间 = 当前到期时间 + 1秒
    t-&amp;gt;expires_at(t-&amp;gt;expiry() + boost::asio::chrono::seconds(1));

    // 异步等待新到期时间
    t-&amp;gt;async_wait(std::bind(print,
        std::placeholders::_1, t, count));
  &amp;#125;
&amp;#125;

int main()
&amp;#123;
  boost::asio::io_context io;

  int count = 0;
  boost::asio::steady_timer t(io, boost::asio::chrono::seconds(1));

  t.async_wait(std::bind(print,
    std::placeholders::_1, &amp;amp;t, &amp;amp;count));

  io.run();

  std::cout &amp;lt;&amp;lt; &amp;quot;Final count is &amp;quot; &amp;lt;&amp;lt; count &amp;lt;&amp;lt; std::endl;

  return 0;
&amp;#125;

// 输出
// 0
// 1
// 2
// 3
// 4
// Final count is 5
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;// 新到期时间 = 当前到期时间 + 1秒
t-&amp;gt;expires_at(t-&amp;gt;expires_at() + boost::asio::chrono::seconds(1));
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;t-&amp;gt;expires_at()&lt;/code&gt; 返回定时器当前的到期时间点（&lt;code&gt;system_clock::time_point&lt;/code&gt; 类型），&lt;code&gt;boost::asio::chrono::seconds(1)&lt;/code&gt;表示一个 ​时间间隔​（&lt;code&gt;duration&lt;/code&gt; 类型）。两者相加会生成新的到期时间点：&lt;/p&gt;
&lt;p&gt;这种设计允许动态调整定时器的触发时间，适用于需要重复执行任务的场景（如每隔&lt;code&gt;1&lt;/code&gt;秒打印一次计数器）。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;​类型匹配的底层原理&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;expires_at()&lt;/code&gt; 的参数类型是 &lt;code&gt;system_clock::time_point&lt;/code&gt;，而 &lt;code&gt;boost::asio::chrono::seconds(1)&lt;/code&gt; 的类型是 &lt;code&gt;duration&lt;/code&gt;,明确指定了时间单位（秒），避免了因隐式类型转换导致的单位混淆（如误用毫秒或微秒）。&lt;br&gt;
&lt;code&gt;Boost.Asio&lt;/code&gt; 的 &lt;code&gt;chrono&lt;/code&gt; 库通过 &lt;strong&gt;​类型推导&lt;/strong&gt; 和 &lt;strong&gt;运算符重载&lt;/strong&gt;，自动将 &lt;code&gt;duration&lt;/code&gt; 转换为 &lt;code&gt;time_point&lt;/code&gt;，确保表达式合法。&lt;br&gt;
若直接使用 &lt;code&gt;t-&amp;gt;expires_at(1)&lt;/code&gt;，编译器会报错，因为 &lt;code&gt;1&lt;/code&gt; 的类型是 &lt;code&gt;int&lt;/code&gt;，无法隐式转换为 &lt;code&gt;time_point&lt;/code&gt;。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;面向对象编程&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;functional&amp;gt; 
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

class printer
&amp;#123;
public:
    // 构造函数，初始化timer_成员和count_成员
    printer(boost::asio::io_context&amp;amp; io)
    : timer_(io, boost::asio::chrono::seconds(1)),  // 初始化timer_成员
      count_(0)                                     // 初始化count_成员
    &amp;#123;
    // bind() 函数将成员函数print绑定到当前对象上，并作为回调函数传递给timer_.async_wait()
        timer_.async_wait(std::bind(&amp;amp;printer::print, this)); 
    &amp;#125;
    // 析构函数
    ~printer()
    &amp;#123;
        std::cout&amp;lt;&amp;lt; &amp;quot;final count is &amp;quot;&amp;lt;&amp;lt; count_ &amp;lt;&amp;lt;std::endl;
    &amp;#125;

    void print()&amp;#123;
        if(count_&amp;lt;5)
        &amp;#123;
            std::cout &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt;std::endl;
            ++count_;
            // 新到期时间 = 当前到期时间 + 1秒
            timer_.expires_at(timer_.expiry() + boost::asio::chrono::seconds(1));
            timer_.async_wait(std::bind(&amp;amp;printer::print,this));
        &amp;#125;
    &amp;#125;

private:
    boost::asio::steady_timer timer_;
    int count_;
&amp;#125;;

int main()
&amp;#123;
  boost::asio::io_context io;
  printer p(io);
  io.run();
  return 0;
&amp;#125;

// 输出
// 0
// 1
// 2
// 3
// 4
// final count is 5
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;优缺点对比&lt;/strong&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;维度&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;​函数式&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;​面向对象&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​代码简洁性&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 代码简短，适合简单场景&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 类定义增加代码量&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​安全性&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 需手动管理指针，易出错&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 自动管理资源，避免悬垂指针&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​扩展性&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 修改需调整参数传递链&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 新增功能只需扩展类方法&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​异步上下文&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 依赖外部变量，多线程下可能竞争&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 成员变量天然隔离，适合多线程异步任务&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​性能开销&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 无虚函数或类结构开销&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 类实例化带来微小内存开销&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;p&gt;&lt;strong&gt;线程安全的异步任务队列（通过 Strand 串行化）&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;functional&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;thread&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;
// 通过 strand_ 序列化回调函数的执行
class printer
&amp;#123;
public:
    printer(boost::asio::io_context&amp;amp; io)
        : strand_(boost::asio::make_strand(io)),     // 初始化strand_成员
        timer1_(io, boost::asio::chrono::seconds(1)),// 初始化timer1_成员
        timer2_(io, boost::asio::chrono::seconds(1)),// 初始化timer2_成员
        count_(0)
    &amp;#123;
        // 使用strand_串行化异步操作,bind_executor()将异步操作绑定到strand_上
        timer1_.async_wait(boost::asio::bind_executor(strand_,
            std::bind(&amp;amp;printer::print1, this)));

        timer2_.async_wait(boost::asio::bind_executor(strand_,
            std::bind(&amp;amp;printer::print2, this)));
    &amp;#125;

    ~printer()
    &amp;#123;
      std::cout &amp;lt;&amp;lt; &amp;quot;Final count is &amp;quot; &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt; std::endl;
    &amp;#125;
    void print1()
    &amp;#123;
        if (count_ &amp;lt; 10)
        &amp;#123;
        std::cout &amp;lt;&amp;lt; &amp;quot;Timer 1: &amp;quot; &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt; std::endl;
        ++count_;

        timer1_.expires_at(timer1_.expiry() + boost::asio::chrono::seconds(1));

        timer1_.async_wait(boost::asio::bind_executor(strand_,
                std::bind(&amp;amp;printer::print1, this)));
        &amp;#125;
    &amp;#125;

    void print2()
    &amp;#123;
        if (count_ &amp;lt; 10)
        &amp;#123;
        std::cout &amp;lt;&amp;lt; &amp;quot;Timer 2: &amp;quot; &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt; std::endl;
        ++count_;

        timer2_.expires_at(timer2_.expiry() + boost::asio::chrono::seconds(1));

        timer2_.async_wait(boost::asio::bind_executor(strand_,
                std::bind(&amp;amp;printer::print2, this)));
        &amp;#125;
    &amp;#125;

private:
  boost::asio::strand&amp;lt;boost::asio::io_context::executor_type&amp;gt; strand_;
  boost::asio::steady_timer timer1_;
  boost::asio::steady_timer timer2_;
  int count_;
&amp;#125;;

int main()
&amp;#123;
  boost::asio::io_context io;
  printer p(io);
  // 创建一个新线程，执行 Lambda 表达式中的代码 (即 io.run())
  std::thread t([&amp;amp;]&amp;#123; io.run(); &amp;#125;);
  io.run();
  // 阻塞主线程，直到 t 线程结束
  t.join();

  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;代码通过多线程运行 &lt;code&gt;io_context &lt;/code&gt;的事件循环，结合 &lt;code&gt;strand_&lt;/code&gt; 的序列化机制，实现了高效的事件响应与线程安全的逻辑处理。虽然有两个线程处理事件，但任务逻辑（&lt;code&gt;print1&lt;/code&gt;/&lt;code&gt;print2&lt;/code&gt;）本质上是单线程化的，因此更准确地说，这是多线程协作处理事件循环，但任务执行是序列化的。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;Lambda&lt;/code&gt; 的捕获方式 [&amp;amp;]&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;[&amp;amp;] 表示以引用方式捕获所有外部变量。&lt;br&gt;
在 &lt;code&gt;Lambda&lt;/code&gt; 内部可以直接访问外部作用域的所有变量（如 &lt;code&gt;io&lt;/code&gt;），且操作的是原变量本身，而非副本。&lt;/li&gt;
&lt;li&gt;​对比其他捕获方式：&lt;br&gt;
[=]：以值方式捕获（创建副本，可能影响性能）。&lt;br&gt;
[io]：仅捕获 io 变量（需显式指定）。&lt;br&gt;
此处 [&amp;amp;] 简化了代码，但需确保 &lt;code&gt;Lambda&lt;/code&gt; 生命周期内外部变量有效。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;代码的多线程机制&lt;br&gt;
&lt;strong&gt;​线程数量与任务类型&lt;/strong&gt;&lt;br&gt;
代码中通过 &lt;code&gt;std::thread t([&amp;amp;]&amp;#123; io.run(); &amp;#125;)&lt;/code&gt; 创建了一个工作线程，主线程也调用 &lt;code&gt;io.run()&lt;/code&gt;，因此 ​总共有两个线程运行 &lt;code&gt;io_context&lt;/code&gt; 的事件循环。这两个线程会并行处理 &lt;code&gt;io_context&lt;/code&gt; 中的异步操作（如定时器到期事件）。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​异步操作的并行性&lt;/strong&gt;&lt;br&gt;
&lt;code&gt;timer1_&lt;/code&gt; 和 &lt;code&gt;timer2_&lt;/code&gt; 是独立的定时器，它们的异步等待操作会被提交到 &lt;code&gt;io_context&lt;/code&gt; 的任务队列中。理论上，这两个定时器的到期事件可能被分配到不同的线程处理。但由于绑定了 &lt;code&gt;strand_&lt;/code&gt;，所有回调会被强制序列化执行，​实际表现为单线程顺序处理​。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;Strand 的核心作用&lt;br&gt;
&lt;strong&gt;​线程安全与顺序保证&lt;/strong&gt;&lt;br&gt;
&lt;code&gt;strand_ &lt;/code&gt;是 &lt;code&gt;Boost.Asio&lt;/code&gt; 提供的一种隐式同步机制，其作用包括：&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;​序列化回调执行：所有通过 &lt;code&gt;strand_&lt;/code&gt; 提交的回调（如 &lt;code&gt;print1&lt;/code&gt; 和 &lt;code&gt;print2&lt;/code&gt;）会按提交顺序依次执行，即使多个线程在运行 &lt;code&gt;io_context&lt;/code&gt;。&lt;br&gt;
​消除数据竞争：对共享资源 &lt;code&gt;count_&lt;/code&gt; 的修改（如&lt;code&gt;++count_&lt;/code&gt;）会被限制在同一个线程上下文中，无需显式加锁。&lt;br&gt;
&lt;strong&gt;​代码中的具体实现&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;timer1_.async_wait(boost::asio::bind_executor(strand_, ...));
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;将定时器的回调函数绑定到 &lt;code&gt;strand_&lt;/code&gt; 的执行器上，确保回调在 &lt;code&gt;strand_ &lt;/code&gt;的调度下运行。因此，即使两个定时器的到期事件被不同线程触发，&lt;code&gt;print1&lt;/code&gt; 和 &lt;code&gt;print2&lt;/code&gt; 也不会并发执行。&lt;/p&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;执行流程示例&lt;br&gt;
假设两个定时器同时到期：
&lt;ol&gt;
&lt;li&gt;​事件触发：&lt;code&gt;timer1_&lt;/code&gt; 和 &lt;code&gt;timer2_&lt;/code&gt; 的到期事件被提交到 &lt;code&gt;io_context&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;​线程分配：事件可能被主线程或工作线程 &lt;code&gt;t&lt;/code&gt; 处理。&lt;/li&gt;
&lt;li&gt;​Strand 调度：无论哪个线程处理事件，回调函数会被 &lt;code&gt;strand_ &lt;/code&gt;序列化。例如：
&lt;ul&gt;
&lt;li&gt;线程1执行 &lt;code&gt;print1&lt;/code&gt; → 输出 &lt;code&gt;Timer 1: 0&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;线程2执行 &lt;code&gt;print2&lt;/code&gt; → 但需等待 &lt;code&gt;print1&lt;/code&gt; 完成后才能执行，输出 &lt;code&gt;Timer 2: 1&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;最终 &lt;code&gt;count_&lt;/code&gt; 会严格递增至10，无并发问题&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;TCP&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;TCP连接&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;TCP连接是面向连接的，可靠的，基于字节流的传输层通信协议。&lt;/li&gt;
&lt;li&gt;TCP连接需要三次握手来建立连接，四次挥手来关闭连接。&lt;/li&gt;
&lt;li&gt;TCP连接的建立和关闭都需要消耗一定的资源，因此需要合理管理TCP连接。&lt;/li&gt;
&lt;li&gt;TCP连接的建立和关闭都需要消耗一定的资源，因此需要合理管理TCP连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;UDP连接&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;UDP连接是无连接的，不可靠的，基于数据报的传输层通信协议。&lt;/li&gt;
&lt;li&gt;UDP连接不需要建立连接，只需要发送数据报即可。&lt;/li&gt;
&lt;li&gt;UDP连接不需要关闭连接，只需要发送数据报即可。&lt;/li&gt;
&lt;li&gt;UDP连接的建立和关闭不需要消耗资源，因此不需要管理UDP连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;TCP和UDP的区别&lt;/strong&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;TCP&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;UDP&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;面向连接&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;无连接&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;可靠&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可靠&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;基于字节流&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;基于数据报&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;需要三次握手&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不需要握手&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;需要四次挥手&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不需要挥手&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;建立和关闭连接需要消耗资源&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;建立和关闭连接不需要消耗资源&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;需要管理连接&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不需要管理连接&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;strong&gt;TCP和UDP的应用场景&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;TCP连接适用于需要可靠传输的场景，如文件传输、邮件发送等。&lt;/li&gt;
&lt;li&gt;UDP连接适用于需要快速传输的场景，如视频直播、实时游戏等。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;TCP和UDP的编程模型&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;TCP连接的编程模型通常包括客户端和服务端两部分，客户端通过 &lt;code&gt;socket&lt;/code&gt; 函数创建一个套接字，然后通过 &lt;code&gt;connect&lt;/code&gt; 函数连接到服务端，然后通过 &lt;code&gt;send&lt;/code&gt; 和 &lt;code&gt;recv&lt;/code&gt; 函数进行数据的发送和接收，最后通过 &lt;code&gt;close&lt;/code&gt; 函数关闭连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;同步TCP时间服务器&#34;&gt;同步TCP时间服务器&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;命令行参数&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int main(int argc, char* argv[])&amp;#123;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;argc（Argument Count）​&lt;/strong&gt;&lt;br&gt;
表示命令行参数的总数量（包括程序名本身）。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;例如，若用户输入 &lt;code&gt;./myprogram arg1 arg2&lt;/code&gt;，则 &lt;code&gt;argc&lt;/code&gt; 的值为 ​3​（程序名 + 2 个参数）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;​&lt;strong&gt;argv[]（Argument Vector）​&lt;/strong&gt;&lt;br&gt;
是一个字符串指针数组，存储所有命令行参数的具体值。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;argv[0]&lt;/code&gt;：程序自身的名称（如 “./myprogram”）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;argv[1]&lt;/code&gt; ~ &lt;code&gt;argv[argc-1]&lt;/code&gt;：用户输入的其他参数。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;argv[argc]&lt;/code&gt;：固定为 NULL（表示数组结束）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;示例代码：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;stdio.h&amp;gt;

int main(int argc, char* argv[]) &amp;#123;
    printf(&amp;quot;参数总数 argc = %d\n&amp;quot;, argc);

    for (int i = 0; i &amp;lt; argc; i++) &amp;#123;
        printf(&amp;quot;argv[%d] = %s\n&amp;quot;, i, argv[i]);
    &amp;#125;

    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;运行示例：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;./myprogram arg1 arg2 arg3
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;输出：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;参数总数 argc = 4
argv[0] = ./myprogram
argv[1] = arg1
argv[2] = arg2
argv[3] = arg3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;同步TCP服务端&lt;/li&gt;
&lt;/ol&gt;
&lt;blockquote&gt;
&lt;p&gt;服务端: 监听端口 13 ,发送时间数据&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;ctime&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;string&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

using boost::asio::ip::tcp;

std::string make_daytime_string() &amp;#123;
    std::time_t now = std::time(nullptr);
    return std::ctime(&amp;amp;now); // 格式示例: &amp;quot;Wed Oct  2 00:00:00 2023\n&amp;quot;
&amp;#125;

int main() &amp;#123;
    try &amp;#123;
        boost::asio::io_context io_context;

        // 监听端口 13 (需管理员权限) 或改用其他端口如 12345
        tcp::acceptor acceptor(io_context, tcp::endpoint(tcp::v4(), 13));

        std::cout &amp;lt;&amp;lt; &amp;quot;Daytime 服务器启动，监听端口: &amp;quot; &amp;lt;&amp;lt; acceptor.local_endpoint().port() &amp;lt;&amp;lt; std::endl;

        for (;;) &amp;#123;
            tcp::socket socket(io_context);
            acceptor.accept(socket); // 阻塞等待客户端连接

            std::cout &amp;lt;&amp;lt; &amp;quot;客户端连接: &amp;quot; &amp;lt;&amp;lt; socket.remote_endpoint() &amp;lt;&amp;lt; std::endl;

            std::string message = make_daytime_string();
            boost::system::error_code ignored_error;

            // 发送时间数据后立即关闭连接
            boost::asio::write(socket, boost::asio::buffer(message), ignored_error);
        &amp;#125;
    &amp;#125; catch (std::exception&amp;amp; e) &amp;#123;
        std::cerr &amp;lt;&amp;lt; &amp;quot;异常: &amp;quot; &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
    &amp;#125;
    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;同步TCP客户端&lt;/li&gt;
&lt;/ol&gt;
&lt;blockquote&gt;
&lt;p&gt;客户端：连接服务器，发送数据，接收响应，关闭连接。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;整体流程&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;**​初始化 I/O 上下文：**创建 io_context 对象，管理所有 I/O 操作。&lt;/li&gt;
&lt;li&gt;**​解析目标地址：**将用户输入的主机名和服务名转换为具体的网络地址列表。&lt;/li&gt;
&lt;li&gt;**​创建套接字：**准备用于通信的套接字对象。&lt;/li&gt;
&lt;li&gt;**​连接服务器：**按地址列表尝试连接，直到成功或全部失败。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;array&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

// using导入某个变量到当前作用域 
using boost::asio::ip::tcp; // tcp命名空间

int main(int argc, char* argv[])
&amp;#123;
  try
  &amp;#123;
    if (argc != 2)
    &amp;#123;
      // std::cerr 通常用于输出错误信息，这些信息不会被重定向到文件或管道，而是直接显示在终端上。
      std::cerr &amp;lt;&amp;lt; &amp;quot;Usage: client &amp;lt;host&amp;gt;&amp;quot; &amp;lt;&amp;lt; std::endl;
      return 1;
    &amp;#125;

    boost::asio::io_context io_context;
    //创建解析器对象，用于将 ​主机名 和 ​服务名/端口号 转换为具体的网络地址（IP + 端口）。
    tcp::resolver resolver(io_context);      // io_context：绑定到同一个 I/O 上下文，确保解析操作由该上下文管理。
    tcp::resolver::results_type endpoints =     
      resolver.resolve(argv[1], &amp;quot;cc&amp;quot;);       // 解析用户输入的主机名和服务名，生成可能的网络端点列表。
    tcp::socket socket(io_context);          // 套接字绑定到同一个 I/O 上下文，确保其操作由该上下文管理。
    boost::asio::connect(socket, endpoints); // 尝试连接到服务器。

    for (;;)
    &amp;#123;
      std::array&amp;lt;char, 128&amp;gt; buf;
      boost::system::error_code error;

      // read_some函数用于从TCP连接中读取数据。buffer函数用于创建一个缓冲区，用于存储读取的数据。size_t类型表示读取的字节数。
      size_t len = socket.read_some(boost::asio::buffer(buf), error); 

      if (error == boost::asio::error::eof) // eof表示连接已关闭。
        break; // Connection closed cleanly by peer.
      else if (error)
        throw boost::system::system_error(error); // Some other error.

      std::cout.write(buf.data(), len);// buf.data()返回缓冲区的指针，len表示读取的字节数。
    &amp;#125;
  &amp;#125;
  catch (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;boost::asio::io_context io_context;&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 创建 I/O 上下文对象，管理所有底层 I/O 操作（如网络通信、定时器等）。&lt;br&gt;
&lt;strong&gt;​原理：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt; 是 &lt;code&gt;Boost.Asio&lt;/code&gt; 的 ​事件循环核心，负责调度和处理异步操作。&lt;br&gt;
所有异步操作（如连接、读写）都需要通过它执行。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;code&gt;tcp::resolver resolver(io_context);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 创建解析器对象，用于将 ​主机名 和 ​服务名/端口号 转换为具体的网络地址（IP + 端口）。&lt;br&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt;：绑定到同一个 I/O 上下文，确保解析操作由该上下文管理。&lt;br&gt;
&lt;strong&gt;​功能：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;解析器 (&lt;code&gt;resolver&lt;/code&gt;) 支持 &lt;code&gt;DNS&lt;/code&gt; 查询，将域名（如 &lt;code&gt;&amp;quot;example.com&amp;quot;&lt;/code&gt;）解析为 IP 地址。&lt;/li&gt;
&lt;li&gt;将服务名（如 &lt;code&gt;&amp;quot;http&amp;quot;&lt;/code&gt;）解析为端口号（如 &lt;code&gt;80&lt;/code&gt;）。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;code&gt;tcp::resolver::results_type endpoints = resolver.resolve(argv[1], &amp;quot;cc&amp;quot;);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 解析用户输入的主机名和服务名，生成可能的网络端点列表。&lt;br&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;argv[1]&lt;/code&gt;：命令行输入的主机名（如 &lt;code&gt;&amp;quot;localhost&amp;quot;&lt;/code&gt; 或 &lt;code&gt;&amp;quot;192.168.1.100&amp;quot;&lt;/code&gt;）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;&amp;quot;cc&amp;quot;&lt;/code&gt;：服务名或端口号。这里可能是自定义的服务名（需系统配置）或直接表示端口号（如 &lt;code&gt;&amp;quot;12345&amp;quot;&lt;/code&gt;）。&lt;br&gt;
&lt;strong&gt;​返回值：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;endpoints&lt;/code&gt; 是一个端点列表，包含所有可能的 IP 地址和端口组合（例如 &lt;code&gt;IPv4&lt;/code&gt; 和 &lt;code&gt;IPv6&lt;/code&gt; 地址）。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;code&gt;tcp::socket socket(io_context);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 创建 &lt;code&gt;TCP&lt;/code&gt; 套接字对象，用于与服务器通信。&lt;br&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt;：套接字绑定到同一个 I/O 上下文，确保其操作由该上下文管理。&lt;br&gt;
&lt;strong&gt;​功能：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;套接字是网络通信的端点，通过它可以发送和接收数据。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;&lt;code&gt;boost::asio::connect(socket, endpoints);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 尝试连接到服务器。&lt;br&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;socket&lt;/code&gt;：上一步创建的套接字。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;endpoints&lt;/code&gt;：解析得到的端点列表。&lt;br&gt;
&lt;strong&gt;​行为：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;按顺序尝试连接 &lt;code&gt;endpoints&lt;/code&gt; 中的每一个端点（如 &lt;code&gt;IPv4&lt;/code&gt; 地址优先，失败后尝试 &lt;code&gt;IPv6&lt;/code&gt;）。&lt;/li&gt;
&lt;li&gt;当某个端点连接成功时，停止尝试。&lt;/li&gt;
&lt;li&gt;如果所有端点均连接失败，抛出异常。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;异步TCP时间服务器&#34;&gt;异步TCP时间服务器&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;主函数入口&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int main()
&amp;#123;
  try
  &amp;#123;
    boost::asio::io_context io_context;      // 创建IO上下文，管理所有异步操作
    tcp_server server(io_context);          // 创建TCP服务器实例，初始化监听
    io_context.run();                       // 启动事件循环，处理异步操作
  &amp;#125;
  catch (std::exception&amp;amp; e)                 // 异常处理
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;
  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt; 是&lt;code&gt;Boost.Asio&lt;/code&gt;的核心，负责调度异步任务。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;tcp_server&lt;/code&gt; 初始化时会开始监听连接。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;io_context.run()&lt;/code&gt; 会阻塞主线程，持续处理异步事件，直到所有任务完成。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;​TCP服务器初始化（tcp_server构造函数）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;tcp_server(boost::asio::io_context&amp;amp; io_context)
  : io_context_(io_context),
    acceptor_(io_context, tcp::endpoint(tcp::v4(), 13)) // 绑定IPv4地址的13端口
&amp;#123;
  start_accept(); // 开始异步等待客户端连接
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;acceptor_&lt;/code&gt; 初始化时绑定到本地13端口。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;start_accept()&lt;/code&gt; 启动异步接受连接的过程。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;strong&gt;异步接受连接（start_accept）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void start_accept()
&amp;#123;
  tcp_connection::pointer new_connection = tcp_connection::create(io_context_); // 创建新连接对象
  acceptor_.async_accept(                       // 异步接受连接
      new_connection-&amp;gt;socket(),
      [this, new_connection](const boost::system::error_code&amp;amp; error) &amp;#123;
          handle_accept(error, new_connection); // 连接完成时调用处理函数
      &amp;#125;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;tcp_connection::create&lt;/code&gt; 创建新的连接对象，其&lt;code&gt;socket&lt;/code&gt;由&lt;code&gt;io_context&lt;/code&gt;管理。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;async_accept&lt;/code&gt; 异步等待客户端连接。当有连接到来时，&lt;code&gt;lambda&lt;/code&gt;被调用，传递错误码和连接对象。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;strong&gt;处理新连接（handle_accept）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void handle_accept(const boost::system::error_code&amp;amp; error, tcp_connection::pointer new_connection)
&amp;#123;
  if (!error)
  &amp;#123;
    new_connection-&amp;gt;start(); // 启动数据发送流程
  &amp;#125;
  start_accept(); // 继续监听下一个连接
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;如果没有错误，调用&lt;code&gt;new_connection-&amp;gt;start()&lt;/code&gt;开始处理客户端请求。&lt;/li&gt;
&lt;li&gt;无论是否出错，再次调用&lt;code&gt;start_accept()&lt;/code&gt;，形成循环监听。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;&lt;strong&gt;TCP连接处理（tcp_connection::start）&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void start()
&amp;#123;
  message_ = make_daytime_string(); // 生成当前时间字符串
  auto self(shared_from_this());    // 获取shared_ptr，延长对象生命周期
  boost::asio::async_write(         // 异步发送数据
      socket_,
      boost::asio::buffer(message_),
      [this, self](const auto&amp;amp; error, size_t bytes) &amp;#123;
          handle_write(error, bytes); // 发送完成后的回调
      &amp;#125;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;make_daytime_string()&lt;/code&gt; 生成当前时间的字符串。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;shared_from_this()&lt;/code&gt; 确保在异步操作期间对象不会被销毁。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;async_write&lt;/code&gt; 异步发送数据，完成后调用&lt;code&gt;handle_write&lt;/code&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;&lt;strong&gt;数据发送完成处理（handle_write）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void handle_write(const boost::system::error_code&amp;amp; /*error*/, size_t /*bytes_transferred*/)
&amp;#123;
  // 此处可添加发送完成后的逻辑，例如关闭连接
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;当前代码未处理发送结果，但可在此处添加错误处理或资源释放逻辑。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;&lt;strong&gt;生成时间字符串（make_daytime_string）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;std::string make_daytime_string()
&amp;#123;
  time_t now = time(0);
  return ctime(&amp;amp;now); // 示例输出：&amp;quot;Wed May 22 15:42:36 2024\n&amp;quot;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;返回的字符串末尾包含换行符，符合Daytime协议标准。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;异步执行流程总结：​&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;服务器启动，监听端口13。&lt;/li&gt;
&lt;li&gt;当客户端连接时，async_accept 完成，触发 handle_accept。&lt;/li&gt;
&lt;li&gt;无错误则调用 start() 发送时间数据。&lt;/li&gt;
&lt;li&gt;数据发送完成后，由 handle_write 处理后续逻辑（当前为空）。&lt;/li&gt;
&lt;li&gt;服务器循环调用 start_accept，持续监听新连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;**关键点：**​&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;​生命周期管理：&lt;/strong&gt; 通过 &lt;code&gt;shared_from_this()&lt;/code&gt; 和 &lt;code&gt;shared_ptr&lt;/code&gt; 确保异步操作期间对象存活。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;​异步链式调用：&lt;/strong&gt; &lt;code&gt;async_accept&lt;/code&gt; →&lt;code&gt; handle_accept&lt;/code&gt; → &lt;code&gt;async_write&lt;/code&gt; → &lt;code&gt;handle_write&lt;/code&gt; 形成异步链。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;​端口重用：&lt;/strong&gt; Daytime协议使用13端口，需确保权限允许（Linux/Mac可能需要sudo运行）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;完整代码：&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;ctime&amp;gt;
#include &amp;lt;functional&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;memory&amp;gt;
#include &amp;lt;string&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

using boost::asio::ip::tcp;

std::string make_daytime_string()
&amp;#123;
  time_t now = time(0);
  return ctime(&amp;amp;now); // 示例输出：&amp;quot;Wed May 22 15:42:36 2024\n&amp;quot;
&amp;#125;

class tcp_connection
  : public std::enable_shared_from_this&amp;lt;tcp_connection&amp;gt;
&amp;#123;
public:
  typedef std::shared_ptr&amp;lt;tcp_connection&amp;gt; pointer;

  static pointer create(boost::asio::io_context&amp;amp; io_context)
  &amp;#123;
    return pointer(new tcp_connection(io_context));
  &amp;#125;

  tcp::socket&amp;amp; socket()
  &amp;#123;
    return socket_;
  &amp;#125;

  void start()
  &amp;#123;
    message_ = make_daytime_string(); // 生成当前时间字符串
    auto self(shared_from_this());    // 获取shared_ptr，延长对象生命周期
    boost::asio::async_write(         // 异步发送数据
        socket_,
        boost::asio::buffer(message_),
        [this, self](const auto&amp;amp; error, size_t bytes) &amp;#123;
            handle_write(error, bytes); // 发送完成后的回调
        &amp;#125;);
  &amp;#125;

private:
  tcp_connection(boost::asio::io_context&amp;amp; io_context)
    : socket_(io_context)
  &amp;#123;
  &amp;#125;

  void handle_write(const boost::system::error_code&amp;amp; /*error*/, size_t /*bytes_transferred*/)
  &amp;#123;
    // 此处可添加发送完成后的逻辑，例如关闭连接
  &amp;#125;

  tcp::socket socket_;
  std::string message_;
&amp;#125;;

class tcp_server
&amp;#123;
public:
  tcp_server(boost::asio::io_context&amp;amp; io_context)
    :io_context_(io_context),
    acceptor_(io_context, tcp::endpoint(tcp::v4(), 13)) // 绑定IPv4地址的13端口
  &amp;#123;
    start_accept(); // 开始异步等待客户端连接
  &amp;#125;

private:
  void start_accept() &amp;#123;
    tcp_connection::pointer new_connection = tcp_connection::create(io_context_);// 创建新连接对象
    acceptor_.async_accept(         // 异步接受连接
        new_connection-&amp;gt;socket(),
        [this, new_connection](const boost::system::error_code&amp;amp; error) &amp;#123;
            // 这里的 this 指向当前 tcp_server 对象
            handle_accept(error, new_connection);
        &amp;#125;
    );
  &amp;#125; 

  void handle_accept(const boost::system::error_code&amp;amp; error, tcp_connection::pointer new_connection)
  &amp;#123;
    if (!error)
    &amp;#123;
      new_connection-&amp;gt;start(); // 启动数据发送流程
    &amp;#125;
    start_accept(); // 继续监听下一个连接
  &amp;#125;

  boost::asio::io_context&amp;amp; io_context_;
  tcp::acceptor acceptor_;
&amp;#125;;

int main()
&amp;#123;
  try
  &amp;#123;
    boost::asio::io_context io_context;      // 创建IO上下文，管理所有异步操作
    tcp_server server(io_context);          // 创建TCP服务器实例，初始化监听
    io_context.run();                       // 启动事件循环，处理异步操作
  &amp;#125;
  catch (std::exception&amp;amp; e)                 // 异常处理
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;
  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;UPD&lt;/h1&gt;
&lt;h2 id=&#34;同步UDP客户端&#34;&gt;同步UDP客户端&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;array&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

using boost::asio::ip::udp;

int main(int argc, char* argv[])
&amp;#123;
  try
  &amp;#123;
    if (argc != 2)
    &amp;#123;
      std::cerr &amp;lt;&amp;lt; &amp;quot;Usage: client &amp;lt;host&amp;gt;&amp;quot; &amp;lt;&amp;lt; std::endl;
      return 1;
    &amp;#125;

    boost::asio::io_context io_context;

    udp::resolver resolver(io_context);
    udp::endpoint receiver_endpoint =
      *resolver.resolve(udp::v4(), argv[1], &amp;quot;daytime&amp;quot;).begin();

    udp::socket socket(io_context);
    socket.open(udp::v4());

    std::array&amp;lt;char, 1&amp;gt; send_buf  = &amp;#123;&amp;#123; 0 &amp;#125;&amp;#125;;
    socket.send_to(boost::asio::buffer(send_buf), receiver_endpoint);

    std::array&amp;lt;char, 128&amp;gt; recv_buf;
    udp::endpoint sender_endpoint;
    size_t len = socket.receive_from(
        boost::asio::buffer(recv_buf), sender_endpoint);

    std::cout.write(recv_buf.data(), len);
  &amp;#125;
  catch (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;异步UDP服务端&#34;&gt;异步UDP服务端&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;array&amp;gt;
#include &amp;lt;ctime&amp;gt;
#include &amp;lt;functional&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;memory&amp;gt;
#include &amp;lt;string&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

using boost::asio::ip::udp;

std::string make_daytime_string()
&amp;#123;
  using namespace std; // For time_t, time and ctime;
  time_t now = time(0);
  return ctime(&amp;amp;now);
&amp;#125;

class udp_server
&amp;#123;
public:
  udp_server(boost::asio::io_context&amp;amp; io_context)
    : socket_(io_context, udp::endpoint(udp::v4(), 13))
  &amp;#123;
    start_receive();
  &amp;#125;

private:
  void start_receive()
  &amp;#123;
    socket_.async_receive_from(
        boost::asio::buffer(recv_buffer_), remote_endpoint_,
        std::bind(&amp;amp;udp_server::handle_receive, this,
          boost::asio::placeholders::error,
          boost::asio::placeholders::bytes_transferred));
  &amp;#125;

  void handle_receive(const boost::system::error_code&amp;amp; error,
      std::size_t /*bytes_transferred*/)
  &amp;#123;
    if (!error)
    &amp;#123;
      std::shared_ptr&amp;lt;std::string&amp;gt; message(
          new std::string(make_daytime_string()));

      socket_.async_send_to(boost::asio::buffer(*message), remote_endpoint_,
          std::bind(&amp;amp;udp_server::handle_send, this, message,
            boost::asio::placeholders::error,
            boost::asio::placeholders::bytes_transferred));

      start_receive();
    &amp;#125;
  &amp;#125;

  void handle_send(std::shared_ptr&amp;lt;std::string&amp;gt; /*message*/,
      const boost::system::error_code&amp;amp; /*error*/,
      std::size_t /*bytes_transferred*/)
  &amp;#123;
  &amp;#125;

  udp::socket socket_;
  udp::endpoint remote_endpoint_;
  std::array&amp;lt;char, 1&amp;gt; recv_buffer_;
&amp;#125;;

int main()
&amp;#123;
  try
  &amp;#123;
    boost::asio::io_context io_context;
    udp_server server(io_context);
    io_context.run();
  &amp;#125;
  catch (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;组合TCP/UDP&lt;/h1&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;array&amp;gt;
#include &amp;lt;ctime&amp;gt;
#include &amp;lt;functional&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;memory&amp;gt;
#include &amp;lt;string&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

using boost::asio::ip::tcp;
using boost::asio::ip::udp;

std::string make_daytime_string()
&amp;#123;
  using namespace std; // For time_t, time and ctime;
  time_t now = time(0);
  return ctime(&amp;amp;now);
&amp;#125;

class tcp_connection
  : public std::enable_shared_from_this&amp;lt;tcp_connection&amp;gt;
&amp;#123;
public:
  typedef std::shared_ptr&amp;lt;tcp_connection&amp;gt; pointer;

  static pointer create(boost::asio::io_context&amp;amp; io_context)
  &amp;#123;
    return pointer(new tcp_connection(io_context));
  &amp;#125;

  tcp::socket&amp;amp; socket()
  &amp;#123;
    return socket_;
  &amp;#125;

  void start()
  &amp;#123;
    message_ = make_daytime_string();

    boost::asio::async_write(socket_, boost::asio::buffer(message_),
        std::bind(&amp;amp;tcp_connection::handle_write, shared_from_this()));
  &amp;#125;

private:
  tcp_connection(boost::asio::io_context&amp;amp; io_context)
    : socket_(io_context)
  &amp;#123;
  &amp;#125;

  void handle_write()
  &amp;#123;
  &amp;#125;

  tcp::socket socket_;
  std::string message_;
&amp;#125;;

class tcp_server
&amp;#123;
public:
  tcp_server(boost::asio::io_context&amp;amp; io_context)
    : io_context_(io_context),
      acceptor_(io_context, tcp::endpoint(tcp::v4(), 13))
  &amp;#123;
    start_accept();
  &amp;#125;

private:
  void start_accept()
  &amp;#123;
    tcp_connection::pointer new_connection =
      tcp_connection::create(io_context_);

    acceptor_.async_accept(new_connection-&amp;gt;socket(),
        std::bind(&amp;amp;tcp_server::handle_accept, this, new_connection,
          boost::asio::placeholders::error));
  &amp;#125;

  void handle_accept(tcp_connection::pointer new_connection,
      const boost::system::error_code&amp;amp; error)
  &amp;#123;
    if (!error)
    &amp;#123;
      new_connection-&amp;gt;start();
    &amp;#125;

    start_accept();
  &amp;#125;

  boost::asio::io_context&amp;amp; io_context_;
  tcp::acceptor acceptor_;
&amp;#125;;

class udp_server
&amp;#123;
public:
  udp_server(boost::asio::io_context&amp;amp; io_context)
    : socket_(io_context, udp::endpoint(udp::v4(), 13))
  &amp;#123;
    start_receive();
  &amp;#125;

private:
  void start_receive()
  &amp;#123;
    socket_.async_receive_from(
        boost::asio::buffer(recv_buffer_), remote_endpoint_,
        std::bind(&amp;amp;udp_server::handle_receive, this,
          boost::asio::placeholders::error));
  &amp;#125;

  void handle_receive(const boost::system::error_code&amp;amp; error)
  &amp;#123;
    if (!error)
    &amp;#123;
      std::shared_ptr&amp;lt;std::string&amp;gt; message(
          new std::string(make_daytime_string()));

      socket_.async_send_to(boost::asio::buffer(*message), remote_endpoint_,
          std::bind(&amp;amp;udp_server::handle_send, this, message));

      start_receive();
    &amp;#125;
  &amp;#125;

  void handle_send(std::shared_ptr&amp;lt;std::string&amp;gt; /*message*/)
  &amp;#123;
  &amp;#125;

  udp::socket socket_;
  udp::endpoint remote_endpoint_;
  std::array&amp;lt;char, 1&amp;gt; recv_buffer_;
&amp;#125;;

int main()
&amp;#123;
  try
  &amp;#123;
    boost::asio::io_context io_context;
    tcp_server server1(io_context);
    udp_server server2(io_context);
    io_context.run();
  &amp;#125;
  catch (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;

 &lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;I/O多路复用&lt;/code&gt;是一种技术，允许一个进程同时监控多个文件描述符，并在其中任何一个文件描述符准备好进行I/O操作时通知进程。这种技术可以提高程序的性能和效率，特别是在需要同时处理多个网络连接或文件描述符的情况下。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1&gt;select&lt;/h1&gt;
&lt;p&gt;函数原型：使用&lt;code&gt;select&lt;/code&gt;这种&lt;code&gt;IO&lt;/code&gt;多路转接方式需要调用一个同名函数&lt;code&gt;select&lt;/code&gt;，这个函数是跨平台的，&lt;code&gt;Linux&lt;/code&gt;、&lt;code&gt;Windows&lt;/code&gt;、&lt;code&gt;MacOS&lt;/code&gt;等操作系统都是支持的。该函数可以委托内核帮助我们检测若干个文件描述符的状态，其实就是检测这些文件描述符对应的读写缓冲区的状态。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;读缓冲区状态：检测里面是否有数据，如果有数据该缓冲区对应的文件描述符就绪&lt;/li&gt;
&lt;li&gt;写缓冲区状态：检测里面是否还有空闲空间，如果有空闲空间该缓冲区对应的文件描述符就绪&lt;/li&gt;
&lt;li&gt;读取异常状态：检测是否发生异常，比如网络异常、文件异常等，如果发生异常该缓冲区对应的文件描述符就绪&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;委托检测的文件描述符遍历检测完毕之后，已就绪的这些满足的文件描述符会通过select()的参数分为3个集合传出，程序员得到这几个集合依次分情况依次处理即可。&lt;/p&gt;
&lt;p&gt;函数原型：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;sys/select.h&amp;gt;
struct timeval &amp;#123;
    time_t tv_sec; /* 秒 */
    suseconds_t tv_usec; /* 微秒 */
&amp;#125;

int select(int nfds, fd_set *readfds, fd_set *writefds, fd_set *exceptfds, struct timeval *timeout);
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;nfds&lt;/code&gt;：需要检测的文件描述符的范围，即检测的文件描述符从0到&lt;code&gt;nfds-1&lt;/code&gt;，&lt;code&gt;nfds&lt;/code&gt;的值通常为待检测的&lt;em&gt;最大文件描述符&lt;/em&gt;加1。(内核允许最大一般是1024)
&lt;ul&gt;
&lt;li&gt;内核需要线程遍历这些集合中的文件描述符，这个值是循环结束的条件。&lt;/li&gt;
&lt;li&gt;在windows中，该参数是无效的，指定为-1即可。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;readfds&lt;/code&gt;：需要检测读状态的文件描述符集合，即检测这些文件描述符对应的读缓冲区状态。
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;传入传出参数&lt;/code&gt;，读集合一般情况下是需要检测的，这样测能直到通过哪些文件描述符接收数据。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;writefds&lt;/code&gt;：需要检测写状态的文件描述符集合，即检测这些文件描述符对应的写缓冲区状态。
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;传入传出参数&lt;/code&gt;，如果不需要使用该参数可以指定为NULL。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;exceptfds&lt;/code&gt;：需要检测异常状态的文件描述符集合，即检测这些文件描述符对应的异常状态。
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;传入传出参数&lt;/code&gt;，如果不需要使用该参数可以指定为NULL。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;timeout&lt;/code&gt;：超时时间，即检测文件描述符状态的超时时间。&lt;/li&gt;
&lt;li&gt;函数返回值：
&lt;ul&gt;
&lt;li&gt;大于&lt;code&gt;0&lt;/code&gt;：成功，返回集合中已就绪的文件描述符的个数。&lt;/li&gt;
&lt;li&gt;等于&lt;code&gt;-1&lt;/code&gt;：则表示出错。&lt;/li&gt;
&lt;li&gt;等于&lt;code&gt;0&lt;/code&gt;：则表示超时。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/images/ioduolu.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;另外初始化&lt;code&gt;fd_set&lt;/code&gt;类型的参数还需要使用相关的一些列操作函数，具体如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void FD_ZERO(fd_set *set); // 将set集合中的所有文件描述符对应的标志位都设置为0，表示集合中没有文件描述符
void FD_SET(int fd, fd_set *set); // 将set集合中的fd文件描述符对应的标志位设置为1，表示集合中有该文件描述符
void FD_CLR(int fd, fd_set *set); // 将set集合中的fd文件描述符对应的标志位设置为0，表示集合中没有该文件描述符
void FD_ISSET(int fd, fd_set *set); // 判断set集合中的fd文件描述符对应的标志位是否为1，如果为1则表示集合中有该文件描述符，否则表示集合中没有该文件描述符
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;poll&lt;/h1&gt;
&lt;p&gt;函数原型：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;poll.h&amp;gt;
struct pollfd &amp;#123;
    int fd; /* 文件描述符 */
    short events; /* 监控的事件 */
    short revents; /* 实际发生的事件 */
&amp;#125;;
int poll(struct pollfd *fds, nfds_t nfds, int timeout);
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;fds&lt;/code&gt;：需要检测的文件描述符集合，即检测这些文件描述符对应的读缓冲区状态、写缓冲区状态、异常状态。
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;传入传出参数&lt;/code&gt;，读集合一般情况下是需要检测的，这样测能直到通过哪些文件描述符接收数据。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;pollfd&lt;/code&gt;结构体数组，每个&lt;code&gt;pollfd&lt;/code&gt;结构体表示一个文件描述符的检测信息，包括文件描述符、检测的事件、实际发生的事件。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;nfds&lt;/code&gt;：需要检测的文件描述符的个数，即检测的文件描述符从0到&lt;code&gt;nfds-1&lt;/code&gt;，&lt;code&gt;nfds&lt;/code&gt;的值通常为待检测的&lt;em&gt;最大文件描述符&lt;/em&gt;加1。
&lt;ul&gt;
&lt;li&gt;内核需要线程遍历这些集合中的文件描述符，这个值是循环结束的条件。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;timeout&lt;/code&gt;：超时时间，即检测文件描述符状态的超时时间。&lt;/li&gt;
&lt;li&gt;函数返回值：
&lt;ul&gt;
&lt;li&gt;大于&lt;code&gt;0&lt;/code&gt;：成功，返回集合中已就绪的文件描述符的个数。&lt;/li&gt;
&lt;li&gt;等于&lt;code&gt;-1&lt;/code&gt;：则表示出错。&lt;/li&gt;
&lt;li&gt;等于&lt;code&gt;0&lt;/code&gt;：则表示超时。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;创建监听的套接字 lfd = socket();&lt;br&gt;
将监听的套接字和本地的IP和端口绑定 bind()&lt;br&gt;
给监听的套接字设置监听 listen()&lt;br&gt;
创建一个文件描述符集合 fd_set，用于存储需要检测读事件的所有的文件描述符&lt;br&gt;
通过 FD_ZERO() 初始化&lt;br&gt;
通过 FD_SET() 将监听的文件描述符放入检测的读集合中&lt;br&gt;
循环调用select()，周期性的对所有的文件描述符进行检测&lt;br&gt;
select() 解除阻塞返回，得到内核传出的满足条件的就绪的文件描述符集合&lt;br&gt;
通过FD_ISSET() 判断集合中的标志位是否为 1&lt;br&gt;
如果这个文件描述符是监听的文件描述符，调用 accept() 和客户端建立连接&lt;br&gt;
将得到的新的通信的文件描述符，通过FD_SET() 放入到检测集合中&lt;br&gt;
如果这个文件描述符是通信的文件描述符，调用通信函数和客户端通信&lt;br&gt;
如果客户端和服务器断开了连接，使用FD_CLR()将这个文件描述符从检测集合中删除&lt;br&gt;
如果没有断开连接，正常通信即可&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;服务端并发实现：&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;stdio.h&amp;gt;
#include &amp;lt;stdlib.h&amp;gt;
#include&amp;lt;unistd.h&amp;gt;
#include&amp;lt;string.h&amp;gt;
#include&amp;lt;arpa/inet.h&amp;gt;
#include &amp;lt;sys/select.h&amp;gt;
int main()&amp;#123;
    // 1. 创建监听的套接字
    int fd = socket(AF_INET, SOCK_STREAM, 0); // IPV4, TCP, 默认协议
    if(fd == -1)&amp;#123;
        perror(&amp;quot;socket&amp;quot;);
        exit(-1);
    &amp;#125;
    // 2. 绑定IP和端口
    struct sockaddr_in saddr;

    saddr.sin_family = AF_INET; // 初始化IPV4
    saddr.sin_port = htons(9999); // 初始化 端口
    saddr.sin_addr.s_addr = INADDR_ANY; // 0=0.0.0.0 
    int ret = bind(fd,(struct sockaddr *)&amp;amp;saddr,sizeof(saddr));
    if(ret == -1)&amp;#123;
        perror(&amp;quot;bind&amp;quot;);
        return -1;
    &amp;#125;

    // 设置监听
    ret = listen(fd,128);
    if(ret == -1)&amp;#123;
        perror(&amp;quot;listen&amp;quot;);
        return -1;
    &amp;#125;

    fd_set redset;
    FD_ZERO(&amp;amp;redset);
    FD_SET(fd,&amp;amp;redset);

    int maxfd = fd;
    while(1)&amp;#123;
        fd_set temp = redset;
        int ret = select(maxfd + 1, &amp;amp;temp, NULL,NULL, NULL);
        // 判断是不是监听fd
        if(FD_ISSET(fd,&amp;amp;temp))&amp;#123;
            // 接受客户端的连接
            int cfd = accept(fd,NULL,NULL);
            FD_SET(cfd, &amp;amp; redset);
            maxfd = cfd &amp;gt; maxfd ?cfd:maxfd ;
        &amp;#125;
        for(int i = 0; i&amp;lt;= maxfd;++i)&amp;#123;
            if(i!=fd &amp;amp;&amp;amp; FD_ISSET(i,&amp;amp;temp))&amp;#123;
                // 接收数据
                char buf[1024];
                int len = recv(i,buf,sizeof(buf),0);
                if(len&amp;gt;0)&amp;#123;
                    printf(&amp;quot;client say : %s\n&amp;quot;,buf);
                    send(i,buf,len,0);
                &amp;#125;
                else if(len == 0)&amp;#123;
                    printf(&amp;quot;客户端断开连接。。\n&amp;quot;);
                    FD_CLR(i,&amp;amp;redset);
                    close(i);
                    break;
                &amp;#125;
                else&amp;#123;
                    perror(&amp;quot;recv&amp;quot;);
                    break;
                &amp;#125;
            &amp;#125;
        &amp;#125;
    &amp;#125;

    // 关闭文件描述符
    close(fd);

    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;select 与 poll 的并发性能比较：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;select&lt;/code&gt;函数的&lt;code&gt;fd_set&lt;/code&gt;类型参数，在每次调用&lt;code&gt;select&lt;/code&gt;函数时，都需要重新设置，而&lt;code&gt;poll&lt;/code&gt;函数的&lt;code&gt;pollfd&lt;/code&gt;类型参数，只需要在第一次调用&lt;code&gt;poll&lt;/code&gt;函数时设置一次，之后每次调用&lt;code&gt;poll&lt;/code&gt;函数时，只需要修改需要检测的文件描述符的&lt;code&gt;pollfd&lt;/code&gt;结构体即可。&lt;/li&gt;
&lt;/ul&gt;

 &lt;blockquote&gt;
&lt;p&gt;Socket是网络编程的一个抽象概念，它是对&lt;code&gt;TCP/IP&lt;/code&gt;协议的封装，提供了一组接口，使得程序员可以更方便地使用网络功能。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1&gt;Socket的原理&lt;/h1&gt;
&lt;p&gt;&lt;code&gt;Socket&lt;/code&gt;的原理是基于&lt;code&gt;TCP/IP&lt;/code&gt;协议的，它通过&lt;code&gt;TCP/IP&lt;/code&gt;协议来传输数据。&lt;code&gt;TCP/IP&lt;/code&gt;协议是一种网络通信协议，它定义了计算机之间如何进行通信。&lt;/p&gt;
&lt;h2 id=&#34;TCP&#34;&gt;TCP&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;TCP&lt;/code&gt;（Transmission Control Protocol）是一种面向连接的、可靠的、基于字节流的传输层通信协议。它提供了一种可靠的、有序的、无重复的数据传输方式。&lt;code&gt;TCP&lt;/code&gt;协议通过三次握手建立连接，通过四次挥手断开连接。在数据传输过程中，&lt;code&gt;TCP&lt;/code&gt;协议会进行流量控制和拥塞控制，以保证数据的可靠传输。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;三次握手：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;客户端向服务器发送一个&lt;code&gt;SYN&lt;/code&gt;包，表示请求建立连接。&lt;/li&gt;
&lt;li&gt;服务器收到&lt;code&gt;SYN&lt;/code&gt;包后，向客户端发送一个&lt;code&gt;SYN-ACK&lt;/code&gt;包，表示同意建立连接。&lt;/li&gt;
&lt;li&gt;客户端收到&lt;code&gt;SYN-ACK&lt;/code&gt;包后，向服务器发送一个ACK包，表示确认建立连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;四次挥手：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;客户端向服务器发送一个&lt;code&gt;FIN&lt;/code&gt;包，表示请求断开连接。&lt;/li&gt;
&lt;li&gt;服务器收到FIN包后，向客户端发送一个&lt;code&gt;ACK&lt;/code&gt;包，表示确认断开连接。&lt;/li&gt;
&lt;li&gt;服务器向客户端发送一个FIN包，表示请求断开连接。&lt;/li&gt;
&lt;li&gt;客户端收到&lt;code&gt;FIN&lt;/code&gt;包后，向服务器发送一个&lt;code&gt;ACK&lt;/code&gt;包，表示确认断开连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/images/tcp.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h1&gt;Socket的使用&lt;/h1&gt;
&lt;h2 id=&#34;服务器端通信流程&#34;&gt;服务器端通信流程&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;创建用于监听的套接字, 这个套接字是一个文件描述符:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;
int lfd = socket( AF_INET, SOCK_STREAM, 0 );

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;socket&lt;/code&gt;接受三个参数，分别是&lt;code&gt;地址族&lt;/code&gt;、&lt;code&gt;套接字类型&lt;/code&gt;和&lt;code&gt;协议类型&lt;/code&gt;。&lt;br&gt;
&lt;code&gt;AF_INET&lt;/code&gt;表示使用&lt;code&gt;IPv4&lt;/code&gt;协议，&lt;code&gt;SOCK_STREAM&lt;/code&gt;表示使用&lt;code&gt;TCP&lt;/code&gt;协议，&lt;code&gt;0&lt;/code&gt;表示使用默认协议。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;绑定套接字到指定的IP地址和端口号:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;struct sockaddr_in serv_addr;
serv_addr.sin_family = AF_INET;
serv_addr.sin_addr.s_addr = htonl(INADDR_ANY); // 使用本地IP地址
serv_addr.sin_port = htons(8888); // 使用指定的端口号

bind( lfd, (struct sockaddr*)&amp;amp;serv_addr, sizeof(serv_addr) );

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;bind&lt;/code&gt;接受三个参数，分别是&lt;code&gt;套接字描述符&lt;/code&gt;、&lt;code&gt;地址结构体&lt;/code&gt;和&lt;code&gt;地址结构体&lt;/code&gt;的大小。&lt;/p&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;监听套接字:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;listen( lfd, 128 );
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;listen接受两个参数，分别是&lt;code&gt;套接字描述符&lt;/code&gt;和&lt;code&gt;监听队列的长度&lt;/code&gt;。&lt;/p&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;接受客户端连接:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;struct sockaddr_in cli_addr;
socklen_t cli_len = sizeof(cli_addr);
int cfd = accept( lfd, (struct sockaddr*)&amp;amp;cli_addr, &amp;amp;cli_len );
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;accept&lt;/code&gt;接受三个参数，分别是&lt;code&gt;套接字描述符&lt;/code&gt;、&lt;code&gt;客户端地址结构体&lt;/code&gt;和&lt;code&gt;客户端地址结构体&lt;/code&gt;的大小。&lt;/p&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;读取客户端发送的数据:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;char buf[1024];
int n = read( cfd, buf, sizeof(buf) );
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;read&lt;/code&gt;接受三个参数，分别是&lt;code&gt;套接字描述符&lt;/code&gt;、&lt;code&gt;缓冲区&lt;/code&gt;和&lt;code&gt;缓冲区大小&lt;/code&gt;。&lt;/p&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;发送数据给客户端:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;write( cfd, &amp;quot;hello world&amp;quot;, 11 );
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;write&lt;/code&gt;接受三个参数，分别是&lt;code&gt;套接字描述符&lt;/code&gt;、&lt;code&gt;数据&lt;/code&gt;和&lt;code&gt;数据大小&lt;/code&gt;。&lt;/p&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;关闭套接字:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;close( lfd );// 关闭监听套接字
close( cfd );// 关闭客户端套接字
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;close&lt;/code&gt;接受一个参数，即&lt;code&gt;套接字描述符&lt;/code&gt;。&lt;/p&gt;
&lt;p&gt;服务端程序的完整代码如下:&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;stdio.h&amp;gt;
#include &amp;lt;stdlib.h&amp;gt;
#include &amp;lt;string.h&amp;gt;
#include &amp;lt;unistd.h&amp;gt;
#include &amp;lt;arpa/inet.h&amp;gt;

int main()
&amp;#123;
    // 1. 创建用于监听的套接字
    int lfd = socket(AF_INET, SOCK_STREAM, 0);
    if (lfd == -1)
    &amp;#123;
        perror(&amp;quot;socket&amp;quot;);
        exit(1);
    &amp;#125;

    // 2. 绑定套接字到指定的IP地址和端口号
    struct sockaddr_in serv_addr;
    serv_addr.sin_family = AF_INET;
    serv_addr.sin_addr.s_addr = htonl(INADDR_ANY);
    serv_addr.sin_port = htons(8888);

    if (bind(lfd, (struct sockaddr*)&amp;amp;serv_addr, sizeof(serv_addr)) == -1)
    &amp;#123;
        perror(&amp;quot;bind&amp;quot;);
        exit(1);
    &amp;#125;

    // 3. 监听套接字
    if (listen(lfd, 128) == -1)
    &amp;#123;
        perror(&amp;quot;listen&amp;quot;);
        exit(1);
    &amp;#125;

    // 4. 接受客户端连接
    struct sockaddr_in cli_addr;
    socklen_t cli_len = sizeof(cli_addr);
    int cfd = accept(lfd, (struct sockaddr*)&amp;amp;cli_addr, &amp;amp;cli_len);
    if (cfd == -1)
    &amp;#123;
        perror(&amp;quot;accept&amp;quot;);
        exit(1);
    &amp;#125;

    // 5. 读取客户端发送的数据
    char buf[1024];
    int n = read(cfd, buf, sizeof(buf));
    if (n == -1)
    &amp;#123;
        perror(&amp;quot;read&amp;quot;);
        exit(1);
    &amp;#125;
    printf(&amp;quot;recv buf: %s\n&amp;quot;, buf);

    // 6. 发送数据给客户端
    if (write(cfd, &amp;quot;hello world&amp;quot;, 11) == -1)
    &amp;#123;
        perror(&amp;quot;write&amp;quot;);
        exit(1);
    &amp;#125;

    // 7. 关闭套接字
    close(lfd);
    close(cfd);

    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;客户端通信流程&#34;&gt;客户端通信流程&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;创建用于连接的套接字:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int cfd = socket( AF_INET, SOCK_STREAM, 0 );
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;连接服务器:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;struct sockaddr_in serv_addr;
serv_addr.sin_family = AF_INET;
serv_addr.sin_addr.s_addr = inet_addr(&amp;quot;127.0.0.1&amp;quot;); // 使用服务器的IP地址
serv_addr.sin_port = htons(8888); // 使用指定的端口号

connect( cfd, (struct sockaddr*)&amp;amp;serv_addr, sizeof(serv_addr) );
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;发送数据给服务器:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;write( cfd, &amp;quot;hello world&amp;quot;, 11 );
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;读取服务器发送的数据:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;char buf[1024];
int n = read( cfd, buf, sizeof(buf) );
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;关闭套接字:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;close( cfd );
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;客户端程序的完整代码如下:&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;stdio.h&amp;gt;
#include &amp;lt;stdlib.h&amp;gt;
#include &amp;lt;string.h&amp;gt;
#include &amp;lt;unistd.h&amp;gt;
#include &amp;lt;arpa/inet.h&amp;gt;

int main()
&amp;#123;
    // 1. 创建用于连接的套接字
    int cfd = socket(AF_INET, SOCK_STREAM, 0);
    if (cfd == -1)
    &amp;#123;
        perror(&amp;quot;socket&amp;quot;);
        exit(1);
    &amp;#125;

    // 2. 连接服务器
    struct sockaddr_in serv_addr;
    serv_addr.sin_family = AF_INET;

    serv_addr.sin_addr.s_addr = inet_addr(&amp;quot;127.0.0.1&amp;quot;);
    serv_addr.sin_port = htons(8888);

    if (connect(cfd, (struct sockaddr*)&amp;amp;serv_addr, sizeof(serv_addr)) == -1)
    &amp;#123;
        perror(&amp;quot;connect&amp;quot;);
        exit(1);
    &amp;#125;

    // 3. 发送数据给服务器
    if (write(cfd, &amp;quot;hello world&amp;quot;, 11) == -1)
    &amp;#123;
        perror(&amp;quot;write&amp;quot;);
        exit(1);
    &amp;#125;

    // 4. 读取服务器发送的数据
    char buf[1024];

    int n = read(cfd, buf, sizeof(buf));
    if (n == -1)
    &amp;#123;
        perror(&amp;quot;read&amp;quot;);
        exit(1);
    &amp;#125;
    printf(&amp;quot;recv buf: %s\n&amp;quot;, buf);

    // 5. 关闭套接字
    close(cfd);

    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;

 &lt;h1&gt;多线程&lt;/h1&gt;
&lt;h2 id=&#34;线程池&#34;&gt;线程池&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;函数指针在线程池中的应用&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;// 定义任务结构体
struct Task &amp;#123;
    void (*function)(void* arg);  // 函数指针
    void* arg;                    // 参数
&amp;#125;;

// 线程池中的工作线程执行任务
void worker_thread(void* arg) &amp;#123;
    while (1) &amp;#123;
        struct Task* task = get_task_from_queue();
        task-&amp;gt;function(task-&amp;gt;arg);  // 执行具体任务
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;**​灵活性：**可以动态添加不同类型的任务（如网络请求、文件操作、计算任务）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;​解耦：&lt;/strong&gt; 线程池代码无需知道任务具体内容，只需调用 &lt;code&gt;function(arg)&lt;/code&gt;。&lt;/li&gt;
&lt;/ul&gt;

 &lt;h1&gt;数据处理&lt;/h1&gt;
&lt;h2 id=&#34;大小端转换&#34;&gt;大小端转换&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;大端和小端是指字节序的存储方式，大端是指高位字节存储在低地址，小端是指低位字节存储在低地址。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ol&gt;
&lt;li&gt;基本定义与存储方式&lt;br&gt;
&lt;strong&gt;大端模式&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;高位字节存放在低地址上，低位字节存放在高地址上。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;0x12345678&lt;/code&gt;在内存中的存储方式为：&lt;code&gt;低地址--&amp;gt; 0x12 0x34 0x56 0x78 --&amp;gt;高地址&lt;/code&gt;&lt;br&gt;
&lt;strong&gt;小端模式&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;高位字节存放在高地址上，低位字节存放在低地址上。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;0x12345678&lt;/code&gt;在内存中的存储方式为： &lt;code&gt;低地址--&amp;gt;  0x78 0x56 0x34 0x12  --&amp;gt;高地址&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;直观对比​（以&lt;code&gt;0x1234&lt;/code&gt;为例）：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;|内存地址	|大端模式|	小端模式|&lt;br&gt;
|–|----|----|----|&lt;br&gt;
|0x4000	|0x12	|0x34|&lt;br&gt;
|0x4001	|0x34	|0x12|&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;设计原因与应用场景&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;为何存在两种模式？&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;硬件差异：&lt;/strong&gt; 不同处理器架构对多字节数据的处理逻辑不同。例如，x86架构（如Intel/AMD CPU）采用小端模式，而PowerPC、MIPS等处理器多采用大端模式。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;​效率考量：&lt;/strong&gt; 小端模式在强制类型转换时无需调整字节顺序（直接截取低地址数据即可），而大端模式便于快速判断符号位（符号位位于低地址）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;应用场景&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;网络通信&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;网络传输：&lt;/strong&gt; TCP/IP协议规定数据传输采用大端模式(网络字节序)，因此小端设备需通过&lt;code&gt;htonl()&lt;/code&gt;等函数转换字节序传输。&lt;/li&gt;
&lt;li&gt;例如，发送&lt;code&gt;0x12345678&lt;/code&gt;时，小端设备需先转换为大端模式&lt;code&gt;0x78563412&lt;/code&gt;再传输，接收后需转回小端。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;跨平台开发&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;文件存储（如二进制文件）需明确字节序，否则不同平台读取时可能出错。&lt;/li&gt;
&lt;li&gt;例如，嵌入式设备与服务器通信时需统一字节序。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;判断当前系统的字节序&lt;/strong&gt;&lt;br&gt;
可通过以下方法检测当前系统是大端还是小端：&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;**联合体法：**利用联合体的内存共享特性读取多字节数据的首字节。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;
#include &amp;lt;iostream&amp;gt;
using namespace std;

bool isLittleEndian()&amp;#123;

    union &amp;#123; 
        uint32_t i; 
        uint8_t c[4]; 
    &amp;#125; test = &amp;#123;0x01020304&amp;#125;;

    return test.c[0] == 0x04; // 若为小端，则首字节为0x04
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;**宏定义法：**利用宏定义计算多字节数据的值。&lt;br&gt;
使用__BYTE_ORDER宏（Linux/Unix）或std::endian::native（C++20）直接判断&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;strong&gt;字节序转换函数&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;大端转小端：&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;uint16_t ntohs(uint16_t netshort);&lt;/code&gt;：将16位无符号整数从网络字节序转换为主机字节序。(windows下为&lt;code&gt;htons&lt;/code&gt;)&lt;/li&gt;
&lt;li&gt;&lt;code&gt;uint32_t ntohl(uint32_t netlong);&lt;/code&gt;：将32位无符号整数从网络字节序转换为主机字节序。(windows下为&lt;code&gt;htonl&lt;/code&gt;)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;小端转大端：&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;uint16_t htons(uint16_t hostshort);&lt;/code&gt;：将16位无符号整数从主机字节序转换到网络字节序。(windows下为&lt;code&gt;ntohs&lt;/code&gt;)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;野指针&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;指向无效内存地址（如未初始化、已释放或越界的内存）的指针，访问时可能导致程序崩溃或数据损坏&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int* p;  
*p = 10;  // p 未初始化，指向随机地址（野指针）  
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;野指针的常见成因:&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;|场景	|描述	|示例|&lt;br&gt;
|–|----|----|----|&lt;br&gt;
|​未初始化指针	|指针变量未赋初值，默认指向随机内存区域| &lt;code&gt;int* p&lt;/code&gt; ;（未初始化为 NULL 或有效地址）|&lt;br&gt;
|​释放后未置空	|&lt;code&gt;free&lt;/code&gt; 或 &lt;code&gt;delete&lt;/code&gt; 后未将指针设为 &lt;code&gt;NULL&lt;/code&gt;，仍指向已释放内存| &lt;code&gt;free(p)&lt;/code&gt; ; 后未执行 &lt;code&gt;p = NULL&lt;/code&gt;;|&lt;br&gt;
|​越界访问	|指针操作超出变量作用域（如返回局部变量地址）|	函数返回栈内存指针导致后续访问失效|&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;规避野指针的最佳实践&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;初始化与置空
&lt;ul&gt;
&lt;li&gt;**初始化：**在声明指针时立即赋初值，避免指向随机内存。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int* p = NULL;  // 初始化为 NULL  
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;**置空：**释放内存后立即将指针置为 &lt;code&gt;NULL&lt;/code&gt;，防止重复释放或访问已释放内存。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;free(p);  
p = NULL;    
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;li&gt;作用域与生命周期管理
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;作用域：&lt;/strong&gt; 确保指针操作在变量有效作用域内，避免返回局部变量地址。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;边界检查：&lt;/strong&gt; 访问数组元素时进行边界检查，防止越界访问。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;智能指针：&lt;/strong&gt; 使用智能指针（如 &lt;code&gt;std::unique_ptr&lt;/code&gt;、&lt;code&gt;std::shared_ptr&lt;/code&gt;）自动管理内存，避免手动释放内存带来的问题。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;多线程环境下的防御措施
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;隔离线程数据：&lt;/strong&gt; 通过动态分配或线程局部存储（thread_local）为每个线程提供独立数据副本，避免数据竞争。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;互斥锁：&lt;/strong&gt; 在多线程访问共享数据时使用互斥锁（mutex）保护，防止并发访问导致的问题。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;原子操作：&lt;/strong&gt; 使用原子操作（atomic）确保对共享数据的访问是线程安全的。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;拷贝构造与运算符重载&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;拷贝构造函数和赋值运算符重载是C++中用于对象复制的两种机制，它们在对象创建和赋值时非常重要。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;拷贝构造函数&#34;&gt;拷贝构造函数&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;拷贝构造函数&lt;/strong&gt;是一种特殊的构造函数，用于创建一个新对象，并将另一个对象的值复制到新对象中。它的定义形式如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName(const ClassName&amp;amp; other);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;其中，&lt;code&gt;ClassName&lt;/code&gt;是类名，&lt;code&gt;other&lt;/code&gt;是另一个对象，类型为&lt;code&gt;ClassName&lt;/code&gt;的引用。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;拷贝构造函数的用途：&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;对象初始化：&lt;/strong&gt; 当使用一个已存在的对象来初始化另一个对象时，拷贝构造函数会被调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName obj1;
ClassName obj2 = obj1;  // 调用拷贝构造函数
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;函数参数传递：&lt;/strong&gt; 当将一个对象作为函数参数传递时，拷贝构造函数会被调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void func(ClassName obj) &amp;#123;
    // ...
&amp;#125;

ClassName obj1;
func(obj1);  // 调用拷贝构造函数
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;strong&gt;函数返回值：&lt;/strong&gt; 当一个函数返回一个对象时，拷贝构造函数会被调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName func() &amp;#123;
    ClassName obj;  // ...
    return obj;  // 调用拷贝构造函数
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;赋值运算符重载&#34;&gt;赋值运算符重载&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;赋值运算符重载&lt;/strong&gt;是一种运算符重载，用于将一个对象的值赋给另一个对象。它的定义形式如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName&amp;amp; operator=(const ClassName&amp;amp; other);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;其中，&lt;code&gt;ClassName&lt;/code&gt;是类名，&lt;code&gt;other&lt;/code&gt;是另一个对象，类型为&lt;code&gt;ClassName&lt;/code&gt;的引用。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;赋值运算符重载的用途：&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;对象赋值：&lt;/strong&gt; 当使用一个已存在的对象来赋值给另一个对象时，赋值运算符重载会被调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName obj1;
ClassName obj2;
obj2 = obj1;  // 调用赋值运算符重载
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;函数返回值：&lt;/strong&gt; 当一个函数返回一个对象时，赋值运算符重载会被调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName func() &amp;#123;
    ClassName obj;  // ...
    return obj;  // 调用赋值运算符重载
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;拷贝构造函数与赋值运算符重载的区别&#34;&gt;拷贝构造函数与赋值运算符重载的区别&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;调用时机：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;拷贝构造函数在对象创建时调用，用于初始化新对象。   - 赋值运算符重载在对象赋值时调用，用于将一个对象的值赋给另一个对象。&lt;/li&gt;
&lt;li&gt;例如，当使用一个已存在的对象来初始化另一个对象时，会调用拷贝构造函数；当使用一个已存在的对象来赋值给另一个对象时，会调用赋值运算符重载。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;参数类型：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;拷贝构造函数的参数类型为&lt;code&gt;const ClassName&amp;amp;&lt;/code&gt;，表示引用另一个对象。   - 赋值运算符重载的参数类型为&lt;code&gt;const ClassName&amp;amp;&lt;/code&gt;，表示引用另一个对象。&lt;/li&gt;
&lt;li&gt;例如，拷贝构造函数的参数类型为&lt;code&gt;const ClassName&amp;amp;&lt;/code&gt;，表示引用另一个对象；赋值运算符重载的参数类型为&lt;code&gt;const ClassName&amp;amp;&lt;/code&gt;，表示引用另一个对象。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;返回值类型：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;拷贝构造函数的返回值类型为&lt;code&gt;ClassName&lt;/code&gt;，表示返回新对象。   - 赋值运算符重载的返回值类型为&lt;code&gt;ClassName&amp;amp;&lt;/code&gt;，表示返回对象的引用。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;拷贝构造函数与赋值运算符重载的示例&#34;&gt;拷贝构造函数与赋值运算符重载的示例&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;class MyClass &amp;#123;
public:
    int data;

    // 拷贝构造函数
    MyClass(const MyClass&amp;amp; other) &amp;#123;
        data = other.data;
    &amp;#125;

    // 赋值运算符重载
    MyClass&amp;amp; operator=(const MyClass&amp;amp; other) &amp;#123;
        if (this != &amp;amp;other) &amp;#123;
            data = other.data;
        &amp;#125;
        return *this;
    &amp;#125;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;拷贝构造函数与赋值运算符重载的最佳实践&#34;&gt;拷贝构造函数与赋值运算符重载的最佳实践&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;避免浅拷贝：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免浅拷贝，即直接复制指针而不是复制指针指向的内容。如果需要复制指针指向的内容，可以使用深拷贝。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免循环引用：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免循环引用，即两个对象相互引用对方。如果需要相互引用，可以使用智能指针（如&lt;code&gt;std::shared_ptr&lt;/code&gt;）来管理对象的生命周期。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免内存泄漏：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免内存泄漏，即释放内存后未将指针置为&lt;code&gt;NULL&lt;/code&gt;。如果需要释放内存，应将指针置为&lt;code&gt;NULL&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免异常安全：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应确保异常安全，即当异常发生时，对象的状态应保持不变。可以使用RAII（Resource Acquisition Is Initialization）模式来确保资源正确释放。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免未定义行为：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免未定义行为，即访问未初始化的指针或释放已释放的内存。可以使用断言（assert）来检测指针是否为&lt;code&gt;NULL&lt;/code&gt;，或使用智能指针来管理内存。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免性能问题：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免性能问题，即复制大量数据或进行复杂的操作。可以使用移动语义（move semantics）来优化性能。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免代码重复：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免代码重复，即重复编写相同的代码。可以使用模板函数或模板类来减少代码重复。&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;浅拷贝与深拷贝&lt;/h1&gt;
&lt;h2 id=&#34;浅拷贝&#34;&gt;浅拷贝&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;仅复制对象的顶层结构（如指针或引用），底层数据仍共享同一内存地址。修改拷贝后的对象会影响原对象&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;场景&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;默认拷贝构造函数：C++ 中类未重写拷贝构造函数时，默认进行浅拷贝。&lt;/li&gt;
&lt;li&gt;​数组/结构体赋值：直接复制数组或结构体时，引用类型成员共享地址&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;风险&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;**​数据竞争：**多线程环境下共享数据可能引发不一致问题。&lt;/li&gt;
&lt;li&gt;**​双重释放：**若共享内存被多次释放，可能导致内存泄漏或崩溃&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;浅拷贝的示例代码如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;class MyClass &amp;#123;
public:
    int data;
    int* ptr;

    MyClass(int value) : data(value), ptr(new int(value)) &amp;#123;&amp;#125;

    // 浅拷贝构造函数
    MyClass(const MyClass&amp;amp; other) : data(other.data), ptr(other.ptr) &amp;#123;&amp;#125;

    // 浅拷贝赋值运算符重载
    MyClass&amp;amp; operator=(const MyClass&amp;amp; other) &amp;#123;
        if (this != &amp;amp;other) &amp;#123;
            data = other.data;
            ptr = other.ptr;
        &amp;#125;
        return *this;
    &amp;#125;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;深拷贝&#34;&gt;深拷贝&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;复制对象的顶层结构及底层数据，确保拷贝后的对象与原对象完全独立。修改拷贝后的对象不会影响原对象&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;实现方式&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;手动递归复制：&lt;/strong&gt; 对于复杂对象，手动递归复制每个成员变量。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;拷贝构造函数：&lt;/strong&gt; 重载拷贝构造函数，实现深拷贝。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;赋值运算符重载：&lt;/strong&gt; 重载赋值运算符重载，实现深拷贝。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;优势&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;数据独立：&lt;/strong&gt; 拷贝后的对象与原对象完全独立，修改一个对象不影响另一个对象。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;内存安全：&lt;/strong&gt; 避免数据竞争和双重释放问题，确保内存安全。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;劣势&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;性能开销：&lt;/strong&gt; 深拷贝需要复制大量数据，可能导致性能开销。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;深拷贝的示例代码如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;class MyClass &amp;#123;
public:
    int data;
    int* ptr;

    MyClass(int value) : data(value), ptr(new int(value)) &amp;#123;&amp;#125;

    // 深拷贝构造函数
    MyClass(const MyClass&amp;amp; other) : data(other.data), ptr(new int(*other.ptr)) &amp;#123;&amp;#125;

    // 深拷贝赋值运算符重载
    MyClass&amp;amp; operator=(const MyClass&amp;amp; other) &amp;#123;
        if (this != &amp;amp;other) &amp;#123;
            data = other.data;
            delete ptr;  // 释放原指针指向的内存
            ptr = new int(*other.ptr);  // 分配新内存并复制数据
        &amp;#125;
        return *this;
    &amp;#125;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;浅拷贝与深拷贝的区别&#34;&gt;浅拷贝与深拷贝的区别&lt;/h2&gt;
&lt;p&gt;| 特性  | 浅拷贝  | 深拷贝   |&lt;/p&gt;
&lt;p&gt;| :---- | :----- | :------ |&lt;/p&gt;
&lt;p&gt;| 复制方式 | 复制顶层结构，共享底层数据 | 复制顶层结构及底层数据，独立内存 |&lt;/p&gt;
&lt;p&gt;| 修改影响 | 修改拷贝后的对象会影响原对象 | 修改拷贝后的对象不影响原对象 |&lt;/p&gt;
&lt;p&gt;| 内存管理 | 共享内存，可能导致数据竞争或内存泄漏 | 独立内存，内存安全 |&lt;/p&gt;
&lt;p&gt;| 性能开销 | 较低，直接复制指针 | 较高，需要复制大量数据 |&lt;/p&gt;
